const items = $input.all();
const courses = [];
for (const item of items) {
  const subject = (item.json.subject || '').trim();
  if (!subject) continue;
  const abbrevMatch = subject.match(/^([A-Z][A-Z0-9\-]+(?:\s+AI)?)\s+(?:Open|Closed|In-house|-)/i);
  if (!abbrevMatch) continue;
