  // Detect English/international courses (won't be on BUR)
  const isEnglish = /\bENG\b|\bFOSS\b|\bEnglish\b/i.test(subject);
  courses.push({ json: {
    source: 'outlook',
    courseAbbrev,
    courseName: courseAbbrev,
    originalSubject: subject,
    isEnglish,
    startDate: item.json.start?.dateTime || null,
    endDate: item.json.end?.dateTime || null,
    startDateShort: item.json.start?.dateTime ? item.json.start.dateTime.substring(0,10) : null,
    endDateShort: item.json.end?.dateTime ? item.json.end.dateTime.substring(0,10) : null,
    location: parts.length>=2 ? parts[parts.length-2] : null,
    trainer: parts.length>=2 ? parts[parts.length-1] : null
  } });
}
if (courses.length === 0) return [{ json: { source: 'outlook', courseName: 'NO_COURSES_FOUND', startDate: null } }];
return courses;

