  if (m) return normalizeAbbrev(m[1].replace(/\u2011/g,'-'));
  const lower=title.toLowerCase().replace(/[\u2014\u2013]/g,'-').trim();
  for (const [name,abbrev] of Object.entries(ABBREV_MAP)) if (lower.includes(name)) return abbrev;
  return title;
}
function extractOnlineAbbrev(title) {
