  let bestMatch='',bestAbbrev='';
  for (const [name,abbrev] of Object.entries(ABBREV_MAP)) {
    if (lower===name&&name.length>bestMatch.length) { bestMatch=name; bestAbbrev=abbrev; }
  }
  if (bestAbbrev) return bestAbbrev;
  for (const [name,abbrev] of Object.entries(ABBREV_MAP)) {
    if (lower.includes(name)&&name.length>bestMatch.length) { bestMatch=name; bestAbbrev=abbrev; }
  }
  return bestAbbrev||withoutDate;
}
function parseOnlineDate(s) {
  if (!s) return '';
  const m=s.match(/(\d{1,2})(?:-\d{1,2})?\.( \d{1,2})\.(\d{4})/);
  if (!m) return '';
  return m[3]+'-'+m[2].padStart(2,'0')+'-'+m[1].padStart(2,'0');
}
